/**
 * Search food database by name or brand.
 * Returns up to `limit` results, sorted by relevance (exact match first, then starts-with, then contains).
 */
export function searchFoodDatabase(query: string, limit = 20): FoodItem[] {
  if (!query.trim()) return [];
  const q = query.toLowerCase().trim();
  
  const exact: FoodItem[] = [];
  const startsWith: FoodItem[] = [];
  const contains: FoodItem[] = [];

  for (const item of FOOD_DATABASE) {
    const brandStr = item.brand ?? "";
    const fullName = (brandStr ? brandStr + " " + item.name : item.name).toLowerCase();
    const nameLower = item.name.toLowerCase();
    const brandLower = brandStr.toLowerCase();
    
    if (nameLower === q || fullName === q) {
      exact.push(item);
    } else if (nameLower.startsWith(q) || brandLower.startsWith(q) || fullName.startsWith(q)) {
      startsWith.push(item);
    } else if (nameLower.includes(q) || brandLower.includes(q) || fullName.includes(q)) {
      contains.push(item);
    }
  }

  return [...exact, ...startsWith, ...contains].slice(0, limit);
}
